import 'package:flutter/material.dart';
import 'package:flutter/rendering.dart';

///Pantalla de chat
class ChatScreen extends StatelessWidget {
  const ChatScreen({super.key});

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      appBar: AppBar(
        leading: Padding(
          padding: const EdgeInsets.all(4.0),
          child: CircleAvatar(
            backgroundImage: NetworkImage(
              'data:image/jpeg;base64,',
            ),
          ),
        ),
        title: Text("Mi amor"),
      ),
      body: _ChatView(),
    );
  }
}

class _ChatView extends StatelessWidget {
  @override
  Widget build(BuildContext context) {
    return SafeArea(
      child: Padding(
        padding: const EdgeInsets.symmetric(horizontal: 8),
        child: Column(
          children: [
            Expanded(
              child: ListView.builder(
                itemCount: 101,
                itemBuilder: (context, index) {
                  return Text('Indice: $index');
                },
              ),
            ),
          ],
        ),
      ),
    );
  }
}


//Apuntes
/*
Un truquito, si una clase por lo general, lleva la palabra Screen retorna un Scaffold
Sacaffold es el esqueleto, la estructura de una pantalla tiene appbar(cabeza) body(cuerpo)
leading es un espacio que tenemos antes del titulo
Padding agrega espacios al rededor de un Widget se usa para separar elementos
CircleAvatar crea un espacio circular, es como un círculo vacío
backgroundImage -> es la imagen que se dibuja como fondo del widget, rellena el CircleAvatar
Container viene a ser como un div. Lo que hicimos fue click derecho, extract widget _chatview
Es como una caja que puede tener color, tamaño, bordes, etc.
Column, retornamos column, porque nos permite colocar varios widgets internos
SafeArea delimita a un area segura el contenido de container
Expanded estira el listview para que ocupe toda la columna
Listview es un widget que muestra sus hijos en una lista desplazable (scrollable)
*/